```Makefile
# ==============================================================================
# 项目名称与编译器配置
# ==============================================================================
TARGET = Template

CC = arm-none-eabi-gcc
AS = arm-none-eabi-gcc -x assembler-with-cpp
OBJCOPY = arm-none-eabi-objcopy
SIZE = arm-none-eabi-size

# ==============================================================================
# 硬件与编译参数配置
# ==============================================================================
CPU = -mcpu=cortex-m4
FPU = -mfpu=fpv4-sp-d16
FLOAT-ABI = -mfloat-abi=hard
MCU = $(CPU) -mthumb $(FPU) $(FLOAT-ABI)

# 宏定义 (非常关键：开启标准库和指定芯片型号)
C_DEFS =  \
-DUSE_STDPERIPH_DRIVER \
-DSTM32F40_41xxx

# 头文件搜索路径 (根据你的目录结构)
C_INCLUDES =  \
-ICMSIS \
-IFWLIB/inc \
-IUSER \
-IMYLIB

# 编译优化级别与调试信息
OPT = -O0 -g
CFLAGS = $(MCU) $(C_DEFS) $(C_INCLUDES) $(OPT) -Wall -fdata-sections -ffunction-sections

# 链接器参数
LDSCRIPT = STM32F407VETx_FLASH.ld
LDFLAGS = $(MCU) -specs=nano.specs -T$(LDSCRIPT) -Wl,-Map=$(TARGET).map,--cref -Wl,--gc-sections

# ==============================================================================
# 源文件收集
# ==============================================================================
# 用户与系统 C 文件
C_SOURCES = \
USER/main.c \
USER/stm32f4xx_it.c \
CMSIS/system_stm32f4xx.c

# 自动获取 FWLIB/src 下所有的 .c 文件
C_SOURCES += $(wildcard FWLIB/src/*.c)

# 汇编启动文件
ASM_SOURCES = CMSIS/startup_stm32f40_41xxx.s

# ==============================================================================
# 编译规则 (请勿随意修改下方内容)
# ==============================================================================
BUILD_DIR = build
OBJECTS = $(addprefix $(BUILD_DIR)/,$(notdir $(C_SOURCES:.c=.o)))
vpath %.c $(sort $(dir $(C_SOURCES)))

OBJECTS += $(addprefix $(BUILD_DIR)/,$(notdir $(ASM_SOURCES:.s=.o)))
vpath %.s $(sort $(dir $(ASM_SOURCES)))

all: $(BUILD_DIR)/$(TARGET).elf $(BUILD_DIR)/$(TARGET).hex $(BUILD_DIR)/$(TARGET).bin

$(BUILD_DIR)/%.o: %.c | $(BUILD_DIR) 
	$(CC) -c $(CFLAGS) $< -o $@

$(BUILD_DIR)/%.o: %.s | $(BUILD_DIR)
	$(AS) -c $(CFLAGS) $< -o $@

$(BUILD_DIR)/$(TARGET).elf: $(OBJECTS)
	$(CC) $(OBJECTS) $(LDFLAGS) -o $@
	$(SIZE) $@

$(BUILD_DIR)/%.hex: $(BUILD_DIR)/%.elf | $(BUILD_DIR)
	$(OBJCOPY) -O ihex $< $@

$(BUILD_DIR)/%.bin: $(BUILD_DIR)/%.elf | $(BUILD_DIR)
	$(OBJCOPY) -O binary -S $< $@

$(BUILD_DIR):
	mkdir $@

clean:
	rm -rf $(BUILD_DIR)
