/* 模拟起始信号：SDA在SCL高电平期间产生下降沿 */
//SCL----
//SDA--
//     --
void Soft_I2C_Start(void){
  //将SCL线和SDA线拉高并延迟1us
  scl_w(1);
  sda_w(1);
  delay(2);
  //仅仅拉低SDA线并延迟1us
  sda_w(0);
  delay(2);
  //拉低SCL，准备发送数据
  scl_w(0);
}
/* 模拟结束信号：SDA在SCL高电平期间产生上升沿 */
//SCL----
//SDA  --
//   --
void Soft_I2C_Start(void){
  //将SCL线拉高，SDA线拉低，为产生上升沿做准备
  scl_w(1);
  sda_w(0);
  delay(2);
  //仅仅拉低SDA线并延迟1us
  sda_w(1);
  delay(2);
  //拉低SCL，因为SDA线在SCL为低电平时产生变化不会有其他作用，较为安全
  scl_w(0);
}
